import{_ as s,o as n,c as l,a4 as t}from"./chunks/framework._in6GHBg.js";const c=JSON.parse('{"title":"生物技术详解","description":"","frontmatter":{},"headers":[],"relativePath":"biology/technology.md","filePath":"biology/technology.md"}'),i={name:"biology/technology.md"};function r(o,a,e,p,g,h){return n(),l("div",null,[...a[0]||(a[0]=[t(`<h1 id="生物技术详解" tabindex="-1">生物技术详解 <a class="header-anchor" href="#生物技术详解" aria-label="Permalink to &quot;生物技术详解&quot;">​</a></h1><p><strong>人类改造生命的工具——从基因到工程</strong></p><hr><h2 id="一、本章地图" tabindex="-1">一、本章地图 <a class="header-anchor" href="#一、本章地图" aria-label="Permalink to &quot;一、本章地图&quot;">​</a></h2><h3 id="核心目标" tabindex="-1">核心目标 <a class="header-anchor" href="#核心目标" aria-label="Permalink to &quot;核心目标&quot;">​</a></h3><p>学完本章，你将：</p><ol><li>理解基因工程的原理和操作步骤⭐</li><li>了解细胞工程的主要技术</li><li>了解发酵工程的基本环节</li><li>认识生物技术的安全性和伦理问题</li></ol><h3 id="知识网络" tabindex="-1">知识网络 <a class="header-anchor" href="#知识网络" aria-label="Permalink to &quot;知识网络&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>生物技术</span></span>
<span class="line"><span>├── 基因工程 ⭐</span></span>
<span class="line"><span>│   ├── 基因工程的基本工具</span></span>
<span class="line"><span>│   ├── 基因工程的基本操作程序</span></span>
<span class="line"><span>│   ├── PCR技术</span></span>
<span class="line"><span>│   └── 基因工程的应用</span></span>
<span class="line"><span>├── 细胞工程</span></span>
<span class="line"><span>│   ├── 植物细胞工程</span></span>
<span class="line"><span>│   ├── 动物细胞工程</span></span>
<span class="line"><span>│   └── 胚胎工程</span></span>
<span class="line"><span>└── 发酵工程</span></span>
<span class="line"><span>    ├── 微生物的培养</span></span>
<span class="line"><span>    └── 发酵过程的控制</span></span></code></pre></div><hr><h2 id="二、概念定义" tabindex="-1">二、概念定义 <a class="header-anchor" href="#二、概念定义" aria-label="Permalink to &quot;二、概念定义&quot;">​</a></h2><h3 id="_2-1-基因工程-⭐" tabindex="-1">2.1 基因工程 ⭐ <a class="header-anchor" href="#_2-1-基因工程-⭐" aria-label="Permalink to &quot;2.1 基因工程 ⭐&quot;">​</a></h3><p><strong>概念</strong>：按照人们的意愿，把一种生物的某种基因提取出来，加以修饰改造，然后放到另一种生物的细胞里，定向地改造生物的遗传性状</p><p><strong>别名</strong>：基因拼接技术、DNA重组技术</p><h4 id="_2-1-1-基因工程的基本工具" tabindex="-1">2.1.1 基因工程的基本工具 <a class="header-anchor" href="#_2-1-1-基因工程的基本工具" aria-label="Permalink to &quot;2.1.1 基因工程的基本工具&quot;">​</a></h4><p><strong>工具1：限制性核酸内切酶（限制酶）</strong></p><ul><li><strong>来源</strong>：主要从原核生物中分离纯化</li><li><strong>功能</strong>：识别双链DNA分子的某种特定核苷酸序列，并使每一条链中特定部位的两个核苷酸之间的磷酸二酯键断开</li><li><strong>结果</strong>：产生黏性末端或平末端</li><li><strong>特点</strong>：一种限制酶只能识别一种特定的核苷酸序列</li></ul><p><strong>工具2：DNA连接酶</strong></p><ul><li><strong>功能</strong>：将双链DNA片段&quot;缝合&quot;起来，恢复被限制酶切开的磷酸二酯键</li><li><strong>类型</strong>：E·coli DNA连接酶、T₄ DNA连接酶</li></ul><p><strong>工具3：载体</strong></p><ul><li><strong>功能</strong>：将外源基因送入受体细胞</li><li><strong>常用载体</strong>：质粒（最常用）、λ噬菌体的衍生物、动植物病毒</li><li><strong>质粒特点</strong>： <ul><li>独立于细菌染色体之外的双链环状DNA分子</li><li>具有自我复制能力</li><li>具有一个至多个限制酶切点</li><li>具有标记基因（供重组DNA的鉴定和选择）</li></ul></li></ul><h4 id="_2-1-2-基因工程的基本操作程序⭐" tabindex="-1">2.1.2 基因工程的基本操作程序⭐ <a class="header-anchor" href="#_2-1-2-基因工程的基本操作程序⭐" aria-label="Permalink to &quot;2.1.2 基因工程的基本操作程序⭐&quot;">​</a></h4><p><strong>四步曲</strong>：</p><p><strong>第一步：目的基因的获取</strong></p><ul><li>方法： <ul><li>从基因文库中获取</li><li>PCR技术扩增</li><li>人工合成（已知序列的小基因）</li></ul></li></ul><p><strong>第二步：基因表达载体的构建</strong>（核心步骤）</p><ul><li>目的：使目的基因在受体细胞中稳定存在，并且可以遗传给下一代，同时使目的基因能够表达和发挥作用</li><li>组成： <ul><li>目的基因</li><li>启动子（RNA聚合酶识别和结合的部位，驱动基因转录）</li><li>终止子</li><li>标记基因（鉴别受体细胞是否含有目的基因）</li></ul></li></ul><p><strong>第三步：将目的基因导入受体细胞</strong></p><table tabindex="0"><thead><tr><th style="text-align:center;">受体细胞</th><th style="text-align:left;">导入方法</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>植物细胞</strong></td><td style="text-align:left;">农杆菌转化法（最常用）、基因枪法、花粉管通道法</td></tr><tr><td style="text-align:center;"><strong>动物细胞</strong></td><td style="text-align:left;">显微注射法</td></tr><tr><td style="text-align:center;"><strong>微生物细胞</strong></td><td style="text-align:left;">Ca²⁺处理法（感受态细胞）</td></tr></tbody></table><p><strong>第四步：目的基因的检测与鉴定</strong></p><table tabindex="0"><thead><tr><th style="text-align:center;">检测水平</th><th style="text-align:left;">方法</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>分子水平</strong></td><td style="text-align:left;">DNA分子杂交（检测目的基因）、分子杂交（检测mRNA）、抗原-抗体杂交（检测蛋白质）</td></tr><tr><td style="text-align:center;"><strong>个体水平</strong></td><td style="text-align:left;">抗虫/抗病接种实验</td></tr></tbody></table><h4 id="_2-1-3-pcr技术" tabindex="-1">2.1.3 PCR技术 <a class="header-anchor" href="#_2-1-3-pcr技术" aria-label="Permalink to &quot;2.1.3 PCR技术&quot;">​</a></h4><p><strong>概念</strong>：多聚酶链式反应，体外快速扩增DNA片段的技术</p><p><strong>原理</strong>：DNA双链复制</p><p><strong>条件</strong>：</p><ul><li>模板DNA</li><li>两种引物</li><li>四种脱氧核苷酸</li><li>Taq DNA聚合酶（热稳定DNA聚合酶）</li><li>缓冲液、Mg²⁺等</li></ul><p><strong>过程</strong>（循环进行）：</p><ol><li><strong>变性</strong>：90-95℃，DNA双链解开</li><li><strong>复性</strong>：55-60℃，引物与模板结合</li><li><strong>延伸</strong>：70-75℃，Taq酶合成新链</li></ol><p><strong>特点</strong>：</p><ul><li>指数扩增：n次循环后，DNA数量增加2ⁿ倍</li><li>快速：几小时可扩增百万倍</li></ul><h4 id="_2-1-4-基因工程的应用" tabindex="-1">2.1.4 基因工程的应用 <a class="header-anchor" href="#_2-1-4-基因工程的应用" aria-label="Permalink to &quot;2.1.4 基因工程的应用&quot;">​</a></h4><p><strong>植物基因工程</strong>：</p><ul><li>抗虫转基因植物（Bt毒蛋白基因）</li><li>抗病转基因植物</li><li>抗逆转基因植物</li><li>改良植物品质</li></ul><p><strong>动物基因工程</strong>：</p><ul><li>提高生长速度</li><li>改善畜产品品质</li><li>生产药物（乳腺生物反应器）</li><li>作器官移植的供体</li></ul><p><strong>基因工程药物</strong>：</p><ul><li>胰岛素、干扰素、白细胞介素等</li></ul><p><strong>基因治疗</strong>：</p><ul><li>概念：把正常基因导入病人体内，使该基因的表达产物发挥功能，从而达到治疗疾病的目的</li><li>类型：体外基因治疗、体内基因治疗</li></ul><h4 id="_2-1-5-蛋白质工程" tabindex="-1">2.1.5 蛋白质工程 <a class="header-anchor" href="#_2-1-5-蛋白质工程" aria-label="Permalink to &quot;2.1.5 蛋白质工程&quot;">​</a></h4><p><strong>概念</strong>：以蛋白质分子的结构规律及其与生物功能的关系作为基础，通过基因修饰或基因合成，对现有蛋白质进行改造，或制造一种新的蛋白质</p><p><strong>与基因工程的关系</strong>：</p><ul><li>基因工程：生产自然界已有的蛋白质</li><li>蛋白质工程：生产自然界不存在的蛋白质（第二代基因工程）</li></ul><p><strong>流程</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>预期蛋白质功能 → 设计蛋白质结构 → 推测氨基酸序列 → 找到对应的脱氧核苷酸序列（基因）→ 基因工程生产</span></span></code></pre></div><hr><h3 id="_2-2-细胞工程" tabindex="-1">2.2 细胞工程 <a class="header-anchor" href="#_2-2-细胞工程" aria-label="Permalink to &quot;2.2 细胞工程&quot;">​</a></h3><p><strong>概念</strong>：应用细胞生物学和分子生物学的原理和方法，通过细胞水平或细胞器水平上的操作，按照人的意愿来改变细胞内的遗传物质或获得细胞产品</p><h4 id="_2-2-1-植物细胞工程" tabindex="-1">2.2.1 植物细胞工程 <a class="header-anchor" href="#_2-2-1-植物细胞工程" aria-label="Permalink to &quot;2.2.1 植物细胞工程&quot;">​</a></h4><p><strong>技术1：植物组织培养</strong></p><p><strong>原理</strong>：植物细胞的全能性（已分化的细胞仍具有发育成完整个体的潜能）</p><p><strong>过程</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>外植体（离体的组织、器官或细胞）→ 脱分化 → 愈伤组织 → 再分化 → 胚状体/丛芽 → 试管苗 → 完整植株</span></span></code></pre></div><p><strong>条件</strong>：</p><ul><li>无菌环境</li><li>适宜的培养基（含植物激素：生长素和细胞分裂素）</li><li>适宜的温度、光照</li></ul><p><strong>应用</strong>：</p><ul><li>快速繁殖</li><li>培育脱毒苗</li><li>生产人工种子</li><li>生产细胞产物</li></ul><p><strong>技术2：植物体细胞杂交</strong></p><p><strong>过程</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>植物细胞A（去壁）→ 原生质体A \\</span></span>
<span class="line"><span>                    → 融合 → 杂种细胞 → 愈伤组织 → 杂种植株</span></span>
<span class="line"><span>植物细胞B（去壁）→ 原生质体B /</span></span></code></pre></div><p><strong>意义</strong>：克服远缘杂交不亲和的障碍</p><p><strong>实例</strong>：白菜-甘蓝、番茄-马铃薯</p><h4 id="_2-2-2-动物细胞工程" tabindex="-1">2.2.2 动物细胞工程 <a class="header-anchor" href="#_2-2-2-动物细胞工程" aria-label="Permalink to &quot;2.2.2 动物细胞工程&quot;">​</a></h4><p><strong>技术1：动物细胞培养</strong></p><p><strong>原理</strong>：细胞增殖</p><p><strong>条件</strong>：</p><ul><li>无菌、无毒环境</li><li>营养（糖、氨基酸、促生长因子、无机盐、微量元素、血清）</li><li>适宜温度和pH</li><li>气体环境（O₂和CO₂）</li></ul><p><strong>过程</strong>：原代培养 → 传代培养</p><p><strong>应用</strong>：生产病毒疫苗、干扰素、单克隆抗体等</p><p><strong>技术2：动物细胞核移植（克隆技术）</strong></p><p><strong>概念</strong>：将动物的一个细胞的细胞核，移入一个已经去掉细胞核的卵母细胞中，使其重组并发育成一个新的胚胎，最终发育为动物个体</p><p><strong>分类</strong>：</p><ul><li>胚胎细胞核移植（较易）</li><li>体细胞核移植（较难）</li></ul><p><strong>实例</strong>：多莉羊</p><p><strong>应用</strong>：</p><ul><li>加速家畜遗传改良</li><li>保护濒危物种</li><li>生产医用蛋白</li><li>作为器官移植的供体</li></ul><p><strong>技术3：动物细胞融合</strong></p><p><strong>诱导因素</strong>：PEG（聚乙二醇）、灭活的病毒、电激</p><p><strong>最重要应用</strong>：单克隆抗体的制备</p><p><strong>单克隆抗体制备过程</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>注射抗原 → 小鼠产生免疫反应 → 取出脾脏B淋巴细胞</span></span>
<span class="line"><span>                                    ↓</span></span>
<span class="line"><span>骨髓瘤细胞（无限增殖）────────→ 细胞融合 → 杂交瘤细胞</span></span>
<span class="line"><span>                                    ↓</span></span>
<span class="line"><span>                筛选（选择性培养基）→ 克隆化培养、抗体检测</span></span>
<span class="line"><span>                                    ↓</span></span>
<span class="line"><span>                            产生专一抗体的杂交瘤细胞</span></span>
<span class="line"><span>                                    ↓</span></span>
<span class="line"><span>                        体外培养或小鼠腹腔内增殖 → 单克隆抗体</span></span></code></pre></div><p><strong>单克隆抗体优点</strong>：</p><ul><li>特异性强</li><li>灵敏度高</li><li>可大量制备</li></ul><p><strong>应用</strong>：诊断试剂、治疗疾病、运载药物（生物导弹）</p><h4 id="_2-2-3-胚胎工程" tabindex="-1">2.2.3 胚胎工程 <a class="header-anchor" href="#_2-2-3-胚胎工程" aria-label="Permalink to &quot;2.2.3 胚胎工程&quot;">​</a></h4><p><strong>概念</strong>：对动物早期胚胎或配子所进行的多种显微操作和处理技术</p><p><strong>主要技术</strong>：</p><ul><li>体外受精</li><li>胚胎移植</li><li>胚胎分割</li><li>胚胎干细胞培养</li></ul><p><strong>胚胎移植</strong>：</p><ul><li>概念：将雌性动物的早期胚胎，或者通过体外受精及其他方式得到的胚胎，移植到同种的、生理状态相同的其他雌性动物体内，使之继续发育为新个体的技术</li><li>地位：胚胎工程的最后一道&quot;工序&quot;</li><li>意义：充分发挥雌性优良个体的繁殖潜力</li></ul><p><strong>胚胎分割</strong>：</p><ul><li>概念：采用机械方法将早期胚胎切割成2等份、4等份或8等份等，经移植获得同卵双胎或多胎的技术</li><li>特点：后代遗传物质相同（无性繁殖）</li><li>要求：分割囊胚阶段的胚胎时，要将内细胞团均等分割</li></ul><hr><h3 id="_2-3-发酵工程" tabindex="-1">2.3 发酵工程 <a class="header-anchor" href="#_2-3-发酵工程" aria-label="Permalink to &quot;2.3 发酵工程&quot;">​</a></h3><p><strong>概念</strong>：利用微生物的特定功能，通过现代工程技术，规模化生产对人类有用的产品</p><p><strong>基本环节</strong>：</p><ol><li><strong>菌种的选育</strong>：诱变育种、基因工程育种</li><li><strong>培养基的配制</strong>：根据微生物营养需求配制</li><li><strong>灭菌</strong>：防止杂菌污染</li><li><strong>接种</strong>：将菌种接入培养基</li><li><strong>发酵过程</strong>：控制温度、pH、溶氧量等</li><li><strong>产品的分离提纯</strong></li></ol><p><strong>影响发酵过程的因素</strong>：</p><ul><li><strong>温度</strong>：影响酶的活性</li><li><strong>pH</strong>：影响酶的活性和细胞膜通透性</li><li><strong>溶氧量</strong>：好氧菌需要充足氧气，厌氧菌需要无氧环境</li><li><strong>营养物质</strong>：碳源、氮源、无机盐等</li></ul><p><strong>应用</strong>：</p><ul><li>食品工业：酿酒、制醋、生产酸奶、味精等</li><li>医药工业：生产抗生素、维生素、激素等</li><li>能源开发：生产乙醇、沼气等</li></ul><hr><h2 id="三、生物技术的安全性和伦理问题" tabindex="-1">三、生物技术的安全性和伦理问题 <a class="header-anchor" href="#三、生物技术的安全性和伦理问题" aria-label="Permalink to &quot;三、生物技术的安全性和伦理问题&quot;">​</a></h2><h3 id="_3-1-转基因生物的安全性" tabindex="-1">3.1 转基因生物的安全性 <a class="header-anchor" href="#_3-1-转基因生物的安全性" aria-label="Permalink to &quot;3.1 转基因生物的安全性&quot;">​</a></h3><p><strong>争论焦点</strong>：</p><ul><li>食物安全：毒性蛋白、过敏原、营养成分改变</li><li>生物安全：对生物多样性的影响</li><li>环境安全：对生态系统稳定性的影响</li></ul><h3 id="_3-2-生物武器" tabindex="-1">3.2 生物武器 <a class="header-anchor" href="#_3-2-生物武器" aria-label="Permalink to &quot;3.2 生物武器&quot;">​</a></h3><p><strong>特点</strong>：致病力强、传染性强、难以防治、成本低</p><p><strong>禁止</strong>：1998年《禁止生物武器公约》</p><h3 id="_3-3-克隆技术的伦理问题" tabindex="-1">3.3 克隆技术的伦理问题 <a class="header-anchor" href="#_3-3-克隆技术的伦理问题" aria-label="Permalink to &quot;3.3 克隆技术的伦理问题&quot;">​</a></h3><ul><li>克隆人违反人类伦理道德</li><li>冲击现有婚姻、家庭、两性关系</li><li>心理和社会地位不确定</li></ul><h3 id="_3-4-试管婴儿与设计试管婴儿" tabindex="-1">3.4 试管婴儿与设计试管婴儿 <a class="header-anchor" href="#_3-4-试管婴儿与设计试管婴儿" aria-label="Permalink to &quot;3.4 试管婴儿与设计试管婴儿&quot;">​</a></h3><p><strong>试管婴儿</strong>：解决不孕不育问题 <strong>设计试管婴儿</strong>：用于救治患者（造血干细胞移植），但引发伦理争议</p><hr><h2 id="四、典型例题" tabindex="-1">四、典型例题 <a class="header-anchor" href="#四、典型例题" aria-label="Permalink to &quot;四、典型例题&quot;">​</a></h2><h3 id="例题1-基因工程操作步骤" tabindex="-1">例题1：基因工程操作步骤 <a class="header-anchor" href="#例题1-基因工程操作步骤" aria-label="Permalink to &quot;例题1：基因工程操作步骤&quot;">​</a></h3><p><strong>题目</strong>：简述基因工程的基本操作程序。</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第一步：获取目的基因</span></span>
<span class="line"><span>第二步：构建基因表达载体（核心步骤）</span></span>
<span class="line"><span>第三步：将目的基因导入受体细胞</span></span>
<span class="line"><span>第四步：目的基因的检测与鉴定</span></span></code></pre></div><hr><h3 id="例题2-pcr技术" tabindex="-1">例题2：PCR技术 <a class="header-anchor" href="#例题2-pcr技术" aria-label="Permalink to &quot;例题2：PCR技术&quot;">​</a></h3><p><strong>题目</strong>：PCR技术为什么需要引物？为什么使用Taq DNA聚合酶？</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>需要引物：DNA聚合酶不能从头开始合成DNA，只能在3&#39;端延伸，</span></span>
<span class="line"><span>所以需要引物提供3&#39;-OH末端。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>使用Taq酶：PCR过程中需要反复加热到90-95℃使DNA变性，</span></span>
<span class="line"><span>普通DNA聚合酶会失活，而Taq DNA聚合酶具有热稳定性，</span></span>
<span class="line"><span>在高温下仍保持活性。</span></span></code></pre></div><hr><h3 id="例题3-单克隆抗体制备" tabindex="-1">例题3：单克隆抗体制备 <a class="header-anchor" href="#例题3-单克隆抗体制备" aria-label="Permalink to &quot;例题3：单克隆抗体制备&quot;">​</a></h3><p><strong>题目</strong>：为什么要将B淋巴细胞与骨髓瘤细胞融合？</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>B淋巴细胞能产生特异性抗体，但在体外不能无限增殖；</span></span>
<span class="line"><span>骨髓瘤细胞能无限增殖，但不能产生抗体。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>融合形成的杂交瘤细胞既能产生特异性抗体，又能无限增殖，</span></span>
<span class="line"><span>可以在体外大规模培养，生产单克隆抗体。</span></span></code></pre></div><hr><h2 id="五、配套练习" tabindex="-1">五、配套练习 <a class="header-anchor" href="#五、配套练习" aria-label="Permalink to &quot;五、配套练习&quot;">​</a></h2><h3 id="基础练习" tabindex="-1">基础练习 <a class="header-anchor" href="#基础练习" aria-label="Permalink to &quot;基础练习&quot;">​</a></h3><p><strong>练习1</strong>：基因工程的三种基本工具是什么？它们各自的功能是什么？</p><p><strong>练习2</strong>：植物组织培养的原理是什么？为什么要强调无菌操作？</p><p><strong>练习3</strong>：单克隆抗体有什么优点？主要应用在哪些方面？</p><p><strong>参考答案</strong>：</p><ul><li>练习1：限制酶（切割DNA）、DNA连接酶（连接DNA片段）、载体（运送目的基因）</li><li>练习2：植物细胞的全能性；防止微生物污染，与植物细胞竞争营养</li><li>练习3：特异性强、灵敏度高、可大量制备；诊断试剂、治疗疾病、运载药物</li></ul><hr><h2 id="六、faq常见问题" tabindex="-1">六、FAQ常见问题 <a class="header-anchor" href="#六、faq常见问题" aria-label="Permalink to &quot;六、FAQ常见问题&quot;">​</a></h2><h3 id="faq-1-限制酶和dna连接酶的作用部位" tabindex="-1">FAQ 1：限制酶和DNA连接酶的作用部位？ <a class="header-anchor" href="#faq-1-限制酶和dna连接酶的作用部位" aria-label="Permalink to &quot;FAQ 1：限制酶和DNA连接酶的作用部位？&quot;">​</a></h3><p><strong>答</strong>：都是磷酸二酯键。限制酶切断磷酸二酯键，DNA连接酶连接磷酸二酯键。</p><h3 id="faq-2-基因表达载体的构建为什么是核心步骤" tabindex="-1">FAQ 2：基因表达载体的构建为什么是核心步骤？ <a class="header-anchor" href="#faq-2-基因表达载体的构建为什么是核心步骤" aria-label="Permalink to &quot;FAQ 2：基因表达载体的构建为什么是核心步骤？&quot;">​</a></h3><p><strong>答</strong>：因为只有构建好表达载体，目的基因才能在受体细胞中稳定存在、遗传给后代并正确表达。</p><h3 id="faq-3-动物细胞培养为什么要加血清" tabindex="-1">FAQ 3：动物细胞培养为什么要加血清？ <a class="header-anchor" href="#faq-3-动物细胞培养为什么要加血清" aria-label="Permalink to &quot;FAQ 3：动物细胞培养为什么要加血清？&quot;">​</a></h3><p><strong>答</strong>：血清中含有多种未知的促生长因子、激素等，目前还不能完全用人工合成培养基替代。</p><h3 id="faq-4-胚胎分割为什么属于无性繁殖" tabindex="-1">FAQ 4：胚胎分割为什么属于无性繁殖？ <a class="header-anchor" href="#faq-4-胚胎分割为什么属于无性繁殖" aria-label="Permalink to &quot;FAQ 4：胚胎分割为什么属于无性繁殖？&quot;">​</a></h3><p><strong>答</strong>：因为分割后的胚胎来自同一个受精卵，遗传物质相同，没有经过两性生殖细胞的结合。</p><hr><p><strong>文档编号</strong>: Bio-Learn-Detail-005<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>`,159)])])}const u=s(i,[["render",r]]);export{c as __pageData,u as default};
